                        var newNote = (p.notes ? p.notes+'\n' : '') + '['+ts+'] '+note
                        setProspects(function(prev){return prev.map(function(x){return x.id===p.id?Object.assign({},x,{notes:newNote}):x})})
                        if(el) el.value = ''
                        toast('Note ajoutée ✓')
